class Solution:
    def kInversePairs(self, n, k):
        MOD = 10**9 + 7
        dp = [0] * (k + 1)
        dp[0] = 1
        for i in range(2, n + 1):
            ndp = [0] * (k + 1)
            for j in range(k + 1):
                total = 0
                for t in range(min(j, i - 1) + 1):
                    total += dp[j - t]
                ndp[j] = total % MOD
            dp = ndp
        return dp[k] % MOD

