class Solution:
    def kInversePairs(self, n, k):
        MOD = 10**9 + 7
        dp = [0] * (k + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            ndp = [0] * (k + 1)
            run = 0
            for j in range(k + 1):
                run = (run + dp[j]) % MOD
                if j - i >= 0:
                    run = (run - dp[j - i]) % MOD
                ndp[j] = run
            dp = ndp
        return dp[k] % MOD

